"""Mutation is the root entry point for all write operations"""
type Mutation {
  """Create a new bead (maps to POST /api/beads)"""
  beadCreate(input: BeadInput!): Bead!

  """Update an existing bead (maps to POST /api/beads/{id})"""
  beadUpdate(
    """Bead ID to update"""
    id: ID!,
    """Fields to update"""
    input: BeadUpdateInput!
  ): Bead!

  """Claim a bead for execution (maps to POST /api/beads/{id}/claim)"""
  beadClaim(
    """Bead ID to claim"""
    id: ID!,
    """Agent or human identifier claiming the bead"""
    assignee: String!
  ): Bead!

  """Unclaim a bead (maps to POST /api/beads/{id}/unclaim)"""
  beadUnclaim(
    """Bead ID to unclaim"""
    id: ID!
  ): Bead!

  """Reopen a closed bead (maps to POST /api/beads/{id}/reopen)"""
  beadReopen(
    """Bead ID to reopen"""
    id: ID!
  ): Bead!

  """Close a bead."""
  beadClose(
    """Bead ID to close"""
    id: ID!,
    """Operator-provided reason"""
    reason: String
  ): Bead!

  """Approve a proposed bead, transitioning it to open (requires non-empty note)"""
  beadApprove(
    """Bead ID to approve"""
    id: ID!,
    """Required operator note explaining the approval decision (empty string is rejected)"""
    note: String!
  ): Bead!

